u_idp_action_form.execution_script:
// Get deployment record
var deployment = new GlideRecord('change_request');
if (deployment.get(formData.deployment_id)) {
    // Create rollback change request
    var rollback = new GlideRecord('change_request');
    rollback.initialize();
    rollback.setValue('type', 'standard');
    rollback.setValue('short_description', 'Rollback: ' + deployment.short_description);
    rollback.setValue('description', 'Rollback deployment ' + formData.deployment_id + ' to previous version. Reason: ' + formData.rollback_reason);
    rollback.setValue('cmdb_ci', deployment.cmdb_ci);
    rollback.setValue('assigned_to', userId);
    rollback.setValue('state', '-5'); // New
    rollback.setValue('rollback_of', formData.deployment_id);
    rollback.insert();

    return {
        success: true,
        resourceId: rollback.sys_id.toString(),
        resourceType: 'change_request',
        message: 'Rollback change request created'
    };
}

return {
    success: false,
    message: 'Deployment not found'
};
